// Cached dropdown in a service
public class CategoryService
{
    private readonly IMemoryCache _cache;
    private readonly AppDbContext _db;

    public CategoryService(IMemoryCache cache, AppDbContext db)
    { _cache = cache; _db = db; }

    public async Task<List<SelectListItem>> GetCategoryOptionsAsync()
    {
        return await _cache.GetOrCreateAsync("category-options", async entry =>
        {
            entry.AbsoluteExpirationRelativeToNow = TimeSpan.FromHours(1);
            return await _db.Categories
                .Select(c => new SelectListItem(c.Name, c.Id.ToString()))
                .ToListAsync();
        });
    }
}

